// Formata segundos para duraГ§ГЈo legГӯvel (ex: 4 minutos e 19 segundos)
const formatDuration = (seconds) => {
  if (!seconds || isNaN(seconds)) return 'NГЈo informado';
  const horas = Math.floor(seconds / 3600);
  const minutos = Math.floor((seconds % 3600) / 60);
  const segs = seconds % 60;
  let resultado = [];
  if (horas > 0) resultado.push(`${horas} hora${horas > 1 ? 's' : ''}`);
  if (minutos > 0) resultado.push(`${minutos} minuto${minutos > 1 ? 's' : ''}`);
  if (segs > 0 || resultado.length === 0) resultado.push(`${segs} segundo${segs > 1 ? 's' : ''}`);
  return resultado.join(', ');
};
// Formata data do YouTube para formato brasileiro (ex: 15 de julho de 2011)
const formatDate = (dateString) => {
  if (!dateString) return 'NГЈo informado';
  try {
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return 'NГЈo informado';
    const meses = [
      'janeiro', 'fevereiro', 'marГ§o', 'abril', 'maio', 'junho',
      'julho', 'agosto', 'setembro', 'outubro', 'novembro', 'dezembro'
    ];
    const dia = date.getDate();
    const mes = meses[date.getMonth()];
    const ano = date.getFullYear();
    return `${dia} de ${mes} de ${ano}`;
  } catch (e) {
    return 'NГЈo informado';
  }
};
// Resumo da descriГ§ГЈo para apenas uma linha
const summarizeDescription = (description) => {
  if (!description) return 'NГЈo informado';
  // Remove quebras de linha e tabs
  let summary = description.replace(/[\n\r\t]+/g, ' ').trim();
  // Limita a ~100 caracteres
  if (summary.length > 100) {
    summary = summary.substring(0, 97) + '...';
  }
  return summary || 'NГЈo informado';
};
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// рҹҺө LAYOUT DO PLAYER DE MГҡSICA (iPhone Style)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
const formatMusicPlayer = (title, artist, duration = null, progress = null, volume = null) => {
  const maxWidth = 42;
  const truncate = (text, maxLen) => {
    if (!text || typeof text !== 'string') return '';
    if (text.length <= maxLen) return text;
    return text.substring(0, maxLen - 3) + '...';
  };
  const safeTitle = title || 'MГәsica';
  const safeArtist = artist || 'Artista';
  const titleDisplay = truncate(safeTitle, maxWidth - 5);
  const artistDisplay = truncate(safeArtist, maxWidth);
  const totalSeconds = duration || 194;
  const currentSeconds = progress !== null ? Math.floor(totalSeconds * progress) : 72;
  const barWidth = 35; // Reduzido em 5 caracteres
  const filledBars = Math.floor((currentSeconds / totalSeconds) * barWidth);
  const emptyBars = barWidth - filledBars;
  const progressBar = 'в”Җ'.repeat(filledBars) + 'в—Ҹ' + 'в”Җ'.repeat(Math.max(0, emptyBars - 1));
  const volPercent = volume !== null ? volume : 75;
  const volFilled = Math.floor((volPercent / 100) * 30);
  const volEmpty = 30 - volFilled;
  const volumeBar = 'в”Җ'.repeat(volFilled) + 'в”Җ'.repeat(volEmpty);
  const innerWidth = maxWidth;
  const pad = (str, len) => str + ' '.repeat(Math.max(0, len - str.length));
  const line = (content) => `${pad(content, innerWidth)}`;
  const spacer = () => ' '.repeat(innerWidth + 2);
  const emoji = 'рҹ…ҙ';
  // Montar o layout linha por linha
  let player = '';
  // Linha 1: iPhone (com espaГ§os Г  direita)
  player += ` ${line('iPhone')}\n`;
  // Linha 2: Nome da mГәsica + emoji
  const titleWithEmoji = titleDisplay + ' ' + emoji;
  player += ` ${line(titleWithEmoji)}\n`;
  // Linha 3: Artista
  player += ` ${line(artistDisplay)}\n`;
  // Linha 4: Barra de progresso (5 caracteres mais curta)
  player += ` ${line(progressBar)}\n`;
  // Linha 5: Controles (25 espaГ§os antes e depois)
  const controls = '                         вҮҶ  в—Ғ  вқҡвқҡ  в–·  вҶ»                         ';
  player += ` ${line(controls)}`;
  // Linha 6: Barra de volume
  const volumeLine = `рҹ”Ҳ  ${volumeBar}  рҹ”Ҡ`;
  player += ` ${line(volumeLine)}`;
  return player;
};
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// рҹҡҰ SISTEMA DE THROTTLING PARA COMANDOS
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
const commandThrottle = new Map(); // userId -> { count, timestamp }
const checkThrottle = (userId) => {
  const now = Date.now();
  const userData = commandThrottle.get(userId) || { count: 0, timestamp: now };
  // Reset a cada 5 segundos
  if (now - userData.timestamp > 5000) {
    userData.count = 0;
    userData.timestamp = now;
  }
  userData.count++;
  commandThrottle.set(userId, userData);
  // MГЎximo 3 comandos por 5 segundos
  return userData.count <= 3;
};
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// рҹ“қ CACHE PARA GROUP DATA (evita ler arquivo toda vez)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
const groupDataCache = new Map(); // groupId -> { data, timestamp }
const GROUP_CACHE_TTL = 5000; // 5 segundos
const getCachedGroupData = (groupId, loadFn) => {
  const cached = groupDataCache.get(groupId);
  const now = Date.now();
  if (cached && (now - cached.timestamp) < GROUP_CACHE_TTL) {
    return Promise.resolve(cached.data);
  }
  return loadFn().then(data => {
    groupDataCache.set(groupId, { data, timestamp: now });
    return data;
  });
};
const invalidateGroupCache = (groupId) => {
  groupDataCache.delete(groupId);
};
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// рҹ”„ FUNГҮГ•ES DE UTILIDADE
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
const writeJsonFile = (filePath, data) => {
  try {
    // ValidaГ§ГЈo de entrada
    if (data === undefined || data === null) {
      console.error(`вқҢ writeJsonFile: Tentativa de salvar dados nulos em ${filePath}`);
      return false;
    }
    // Testa se dados sГЈo serializГЎveis
    let jsonString;
    try {
      jsonString = JSON.stringify(data, null, 2);
    } catch (stringifyError) {
      console.error(`вқҢ writeJsonFile: Dados nГЈo serializГЎveis para ${filePath}:`, stringifyError.message);
      return false;
    }
    // Valida JSON gerado
    try {
      JSON.parse(jsonString);
    } catch (validateError) {
      console.error(`вқҢ writeJsonFile: JSON invГЎlido gerado para ${filePath}`);
      return false;
    }
    ensureDirectoryExists(pathz.dirname(filePath));
    // Escreve em arquivo temporГЎrio primeiro (operaГ§ГЈo atГҙmica)
    const tempPath = filePath + '.tmp';
    fs.writeFileSync(tempPath, jsonString, 'utf-8');
    // Verifica integridade do arquivo temporГЎrio
    try {
      const writtenContent = fs.readFileSync(tempPath, 'utf-8');
      JSON.parse(writtenContent);
    } catch (verifyError) {
      console.error(`вқҢ writeJsonFile: VerificaГ§ГЈo falhou para ${filePath}`);
      try { fs.unlinkSync(tempPath); } catch (e) { }
      return false;
    }
    // Move arquivo temporГЎrio para destino (atГҙmico)
    fs.renameSync(tempPath, filePath);
    return true;
  } catch (error) {
    console.error(`вқҢ Erro ao escrever JSON em ${filePath}:`, error.message);
    // Tenta limpar arquivo temporГЎrio
    try {
      const tempPath = filePath + '.tmp';
      if (fs.existsSync(tempPath)) fs.unlinkSync(tempPath);
    } catch (e) { }
    return false;
  }
};
/**
 * VersГЈo assГӯncrona do writeJsonFile - nГЈo bloqueia o event loop
 * @param {string} filePath - Caminho do arquivo
 * @param {object} data - Dados a serem salvos
 * @returns {Promise<boolean>}
 */
const writeJsonFileAsync = async (filePath, data) => {
  try {
    if (data === undefined || data === null) {
      console.error(`вқҢ writeJsonFileAsync: Tentativa de salvar dados nulos em ${filePath}`);
      return false;
    }
    let jsonString;
    try {
      jsonString = JSON.stringify(data, null, 2);
    } catch (stringifyError) {
      console.error(`вқҢ writeJsonFileAsync: Dados nГЈo serializГЎveis para ${filePath}:`, stringifyError.message);
      return false;
    }
    // Valida JSON gerado
    try {
      JSON.parse(jsonString);
    } catch (validateError) {
      console.error(`вқҢ writeJsonFileAsync: JSON invГЎlido gerado para ${filePath}`);
      return false;
    }
    await fsPromises.mkdir(pathz.dirname(filePath), { recursive: true });
    // Escreve em arquivo temporГЎrio primeiro (operaГ§ГЈo atГҙmica)
    const tempPath = filePath + '.tmp';
    await fsPromises.writeFile(tempPath, jsonString, 'utf-8');
    // Verifica integridade
    try {
      const writtenContent = await fsPromises.readFile(tempPath, 'utf-8');
      JSON.parse(writtenContent);
    } catch (verifyError) {
      console.error(`вқҢ writeJsonFileAsync: VerificaГ§ГЈo falhou para ${filePath}`);
      try { await fsPromises.unlink(tempPath); } catch (e) { }
      return false;
    }
    // Move arquivo temporГЎrio para destino (atГҙmico)
    await fsPromises.rename(tempPath, filePath);
    return true;
  } catch (error) {
    console.error(`вқҢ Erro ao escrever JSON async em ${filePath}:`, error.message);
    try {
      const tempPath = filePath + '.tmp';
      await fsPromises.unlink(tempPath).catch(() => { });
    } catch (e) { }
    return false;
  }
};
/**
 * Leitura assГӯncrona de arquivo JSON
 * @param {string} filePath - Caminho do arquivo
 * @param {object} defaultValue - Valor padrГЈo se arquivo nГЈo existir
 * @returns {Promise<object>}
 */
const readJsonFileAsync = async (filePath, defaultValue = {}) => {
  try {
    const content = await fsPromises.readFile(filePath, 'utf-8');
    return JSON.parse(content);
  } catch (error) {
    if (error.code !== 'ENOENT') {
      console.error(`вқҢ Erro ao ler JSON async de ${filePath}:`, error.message);
    }
    return defaultValue;
  }
};
/**
 * Verifica se arquivo existe (assГӯncrono)
 * @param {string} filePath - Caminho do arquivo
 * @returns {Promise<boolean>}
 */
const fileExistsAsync = async (filePath) => {
  try {
    await fsPromises.access(filePath);
    return true;
  } catch {
    return false;
  }
};
