  const site_vex = config.site_vex
  const debug = config.debug;
  const lidowner = config.lidowner;
  // Sistema de degradaГ§ГЈo automГЎtica de pets
  function applyPetDegradation(pets) {
    if (!Array.isArray(pets) || pets.length === 0) return { changed: false };
    const now = Date.now();
    const oneHour = 3600000; // 1 hora em ms
    const oneDayInHours = 24; // DegradaГ§ГЈo total em 24 horas se nГЈo cuidar
    let changed = false;
    pets.forEach(pet => {
      // Inicializa lastUpdate se nГЈo existir
      if (!pet.lastUpdate) {
        pet.lastUpdate = now;
        changed = true;
        return;
      }
      const timePassed = now - pet.lastUpdate;
      const hoursPassed = timePassed / oneHour;
      // SГі degrada se passou mais de 1 hora
      if (hoursPassed >= 1) {
        // Calcula degradaГ§ГЈo proporcional ao tempo
        const hungerDegrade = Math.floor(hoursPassed * (100 / oneDayInHours)); // ~4.17 por hora
        const moodDegrade = Math.floor(hoursPassed * (100 / (oneDayInHours * 2))); // ~2.08 por hora (degrada mais devagar)
        // Aplica degradaГ§ГЈo
        const oldHunger = pet.hunger || 100;
        const oldMood = pet.mood || 100;
        pet.hunger = Math.max(0, oldHunger - hungerDegrade);
        pet.mood = Math.max(0, oldMood - moodDegrade);
        // Se fome estГЎ muito baixa, humor degrada mais rГЎpido
        if (pet.hunger < 30) {
          pet.mood = Math.max(0, pet.mood - Math.floor(hoursPassed * 5));
        }
        // Se fome chegou a 0, pet perde HP gradualmente
        if (pet.hunger === 0 && hoursPassed >= 2) {
          const hpLoss = Math.floor(hoursPassed * (pet.maxHp * 0.02)); // 2% do HP mГЎximo por hora
          pet.hp = Math.max(1, (pet.hp || pet.maxHp) - hpLoss); // Nunca deixa morrer (mГӯnimo 1 HP)
        }
        // Atualiza timestamp
        pet.lastUpdate = now;
        changed = true;
      }
    });
    return { changed };
  }
  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  // FUNГҮГ•ES AUXILIARES DO SISTEMA RPG
