          text += `в”Ӯ рҹ’ө Moedas: *-${loss.toLocaleString()}*\n`;
          text += `в”Ӯ\n`;
          text += `в””в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”ҳ\n\n`;
