        const actions = [
          `${pushname} deu um tapa em @${target.split('@')[0]}! рҹ‘Ӣрҹ’Ҙ`,
          `PAH! ${pushname} acertou @${target.split('@')[0]} em cheio! рҹҳӨ`,
          `${pushname} nГЈo teve piedade e bateu em @${target.split('@')[0]}! рҹ’ў`,
          `SMACK! ${pushname} deu um tapГЈo em @${target.split('@')[0]}! рҹҳ `
        ];
        return reply(actions[Math.floor(Math.random() * actions.length)], { mentions: [target] });
