        const protectCost = 2000;
        if (me.wallet < protectCost) {
          return reply(`рҹ’° VocГӘ precisa de ${protectCost.toLocaleString()} moedas para proteger alguГ©m!`);
        }
        me.wallet -= protectCost;
        const targetData = getEcoUser(econ, target);
