          if (!fs.existsSync(updateScriptPath)) {
            return reply("вқҢ Script de atualizaГ§ГЈo nГЈo encontrado!\n\nрҹ“Ӯ Caminho esperado: dados/src/.scripts/update.js");
          }
          // Iniciar atualizaГ§ГЈo diretamente
          await reply("рҹҡҖ *INICIANDO ATUALIZAГҮГғO...*\n\nвҸёпёҸ Pausando processamento de mensagens...");
          // Pausa o processamento de mensagens
