            const menuVideoPath = __dirname + '/../midias/menu.mp4';
            const menuImagePath = __dirname + '/../midias/menu.jpg';
            // Verifica se existe mГӯdia global
            const hasGlobalVideo = fs.existsSync(menuVideoPath);
