          const stats = vipCommandsManager.getVipStats();
          let statsText = `рҹ“Ҡ *ESTATГҚSTICAS DO SISTEMA VIP*\n\n`;
          statsText += `в•ӯв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв•®\n`;
